    for method in METHODS:
        method_weight(method, cfg["seed"])

    class_counts = {}
    weighted = 0
    flagged = 0
    total_bytes = 0
    hour_paths = {}
    hour_path_maxes = {}

    for e in entries:
        cls = status_class(e["status"])
        class_counts[cls] = class_counts.get(cls, 0) + 1
        weighted += method_weight(e["method"], cfg["seed"])
        if e["host"] in suspicious_set:
            flagged += 1
        total_bytes += e["size"]

